import{_ as e,p as o,q as d,a1 as i}from"./framework-96b046e1.js";const t="/images/并行数据传输.png",c="/images/串行数据传输.png",l="/images/SPI接线.png",s="/images/SPI从机选择.png",r="/images/spi-clk-out.png",p="/images/spi-cs-out-low.png",a="/images/spi-mosi-out.png",n="/images/spi-miso-out.png",g="/images/spi-001.png",h={},S=i('<p><code>SPI</code>、<code>I2C</code> 和 <code>UART</code> 比 <code>USB</code>、<code>以太网</code>、<code>蓝牙</code>和 <code>WiFi</code> 等协议慢很多，但它们简单得多，硬件和系统资源使用更少。<code>SPI</code>、<code>I2C</code> 和 <code>UART</code> 非常适合微控制器之间以及微控制器和传感器之间的通信，无需传输大量高速数据。</p><h2 id="串行与并行通信" tabindex="-1"><a class="header-anchor" href="#串行与并行通信" aria-hidden="true">#</a> 串行与并行通信</h2><p>电子设备通过设备之间物理连接的电线发送数据位来相互通信。这有点像一个单词中的字母，只存在于单词表中的 26 个字母内，一个位是二进制的，只能是 1 或 0。通过电压的快速变化，位从一个设备转移到另一个设备。在一个操作在 5V 的系统中，0 位作为 0V 的短脉冲进行通信，1位通过 5V 的短脉冲进行通信。</p><p>数据位可以并行或串行形式传输。在并行通信中，数据位均同时发送，每个数据位均通过单独的导线发送。下图显示二进制字母&quot;C&quot;的并行传输（01000011）：</p><p><img src="'+t+'" alt=""></p><p>在串行通信中，这些位通过单个线逐一发送。下图显示二进制字母&quot;C&quot;的串行传输（01000011）：</p><p><img src="'+c+'" alt=""></p><h2 id="spi-协议" tabindex="-1"><a class="header-anchor" href="#spi-协议" aria-hidden="true">#</a> SPI 协议</h2><p><code>SPI</code> 是串行外设接口（<code>Serial Peripheral Interface</code>）的缩写，是一种<strong>高速</strong>的，<strong>全双工</strong>，<strong>同步</strong>的通信总线，并且在芯片的管脚上只占用四根线，节约了芯片的管脚，同时为 PCB 的布局上节省空间，提供方便，正是出于这种简单易用的特性，越来越多的芯片集成了这种通信协议。</p><p><code>SPI</code> 的一个独特好处是<em>数据可以不间断地传输</em>。任何数量的位都可以在连续流中发送或接收。使用 <code>I2C</code> 和 <code>UART</code>，数据以数据<strong>包</strong>方式发送，仅限于特定数量的位。启动和停止条件定义每个数据包的开始和结束，因此数据在传输过程中中断。</p><p>通过 <code>SPI</code> 通信的设备处于<strong>主从</strong>关系中。<strong>主机</strong>是控制装置（通常是微控制器），而<strong>从机</strong>（通常是<em>传感器</em>、<em>显示器</em>或<em>内存芯片</em>）接受主机的指令。<code>SPI</code> 最简单的配置是单主机、单从机系统，但一个主机可以控制多个从机。</p><p><img src="'+l+'" alt=""></p><ul><li><code>MOSI</code>（主机输出/从机输入）–主机向从机发送数据的线</li><li><code>MISO</code>（主机输入/从机输出）–从机向主机发送数据的线</li><li><code>SCLK</code>（时钟） -时钟信号线</li><li><code>SS/CS</code>（从机选择/芯片选择）-用于主机选择给哪个从机发送数据的线</li></ul><h3 id="spi-的工作原理" tabindex="-1"><a class="header-anchor" href="#spi-的工作原理" aria-hidden="true">#</a> SPI 的工作原理</h3><ul><li>时钟</li></ul><p><strong>时钟信号</strong>用于<strong>同步</strong>主机和从机之间的数据采样。每个时钟周期传输一位数据，因此数据传输的速度由时钟信号的频率决定。<code>SPI</code> 通信始终由主发起，并由主机配置和产生时钟信号。</p><p>设备共享时钟信号的任何通信协议都称为同步通信协议。<code>SPI</code> 是一种同步通信协议。也有不使用时钟信号的异步方法。例如，在 <code>UART</code> 通信中，双方被设置为预先配置的 <code>baud</code> 速率，该速率和时间决定数据传输的速度和时间。</p><p><code>SPI</code> 中的时钟信号可以使用<strong>时钟极性</strong>和<strong>时钟相位</strong>的特性进行修改。这两个属性协同工作，以定义位的<strong>输出时间</strong>和<strong>采样时间</strong>。<strong>时钟极性</strong>可以由主机设置，以便对时钟周期的<strong>上升沿</strong>或<strong>下降沿</strong>进行位的输出和采样。<strong>时钟相位</strong>可以设置为在时钟周期的<strong>第一边缘</strong>或<strong>第二边缘</strong>进行输出和采样，无论它是上升还是下降。</p><ul><li>从机选择</li></ul><p><img src="'+s+'" alt=""></p><p>主机可以通过将从机的 <code>CS/SS</code> 线设置为低电平来选择它想与哪个从机通信。在闲置、非传输状态下，从机选择线保持在高压水平。主机上如果可以提供多个 <code>CS/SS</code> 引脚，允许多个从机并行连接。如果只有一个 <code>CS/SS</code> 引脚存在，多个从机可以通过菊花链的形式连接到主机。</p><ul><li>MOSI 和 MISO</li></ul><p>主机通过串行 <code>MOSI</code> 线，逐位的发送数据给从机。从机从主机的 <code>MOSI</code> 管脚接收数据。主机给从机发送数据，通常首先发送最高有效位。</p><p>从机也可以通过 <code>MISO</code> 串行线给主机回发数据。数据由从机回发给主机通常首先发送最低有效位。</p><h3 id="spi-数据传输步骤" tabindex="-1"><a class="header-anchor" href="#spi-数据传输步骤" aria-hidden="true">#</a> SPI 数据传输步骤</h3><ul><li>主机输出时钟信号</li></ul><p><img src="'+r+'" alt=""></p><ul><li>主机拉低 SS/CS 片选线，激活对应从机</li></ul><p><img src="'+p+'" alt=""></p><ul><li><p>主机通过 MOSI 线发送数据给从机，一次发送一位，从机读取收到的数据位 <img src="'+a+'" alt=""></p></li><li><p>如果需要响应，从机则通过 MISO 线返回数据，一次发送一位，主机读取收到的数据位</p></li></ul><p><img src="'+n+'" alt=""></p><h3 id="spi-的优缺点" tabindex="-1"><a class="header-anchor" href="#spi-的优缺点" aria-hidden="true">#</a> SPI 的优缺点</h3><ul><li>优点 <ul><li>没有启动和停止位，因此数据可以连续流式传输而不中断；</li><li>没有像 I2C 这样复杂的从机寻址系统；</li><li>数据传输率高于 I2C（几乎是 I2C 的两倍）；</li><li>分离 MISO 和 MOSI 线，以便可以同时发送和接收数据。</li></ul></li><li>缺点 <ul><li>使用四根电线（I2C 和 UART 使用两根线）；</li><li>不确认数据已成功接收（I2C 有此）；</li><li>没有任何形式的错误检查，如在 UART 中的校验位；</li><li>只允许一个主机</li></ul></li></ul><h2 id="时钟极性-时钟相位" tabindex="-1"><a class="header-anchor" href="#时钟极性-时钟相位" aria-hidden="true">#</a> 时钟极性&amp;时钟相位</h2><p><code>SPI</code>的极性<code>Polarity</code>和相位<code>Phase</code>，最常见的写法是<code>CPOL</code>和<code>CPHA</code>。</p><p><code>Edge</code> 边沿，即时钟发生变化的时刻，上边沿（<code>rising edge</code>）和上边沿（<code>falling edge</code>）。</p><p>前一个边沿（第一个边沿），对于开始电压为高电平1，那么就是1变成0的时候，对于开始电压为低电平0，那么就是0变成1的时候。</p><p>后一个边沿（第二个边沿），对于开始电压为高电平1，那么就是0变成1的时候（极在第一次1变成0之后，才可能有后面的0变成1），对于开始电压为低电平0，那么就是1变成0的时候。</p><ul><li>极性=CPOL (极性就是CLK空闲时的状态，可能为高电平或低电平)</li><li>相位=CPHA (相位代表在时钟的第几个边沿采集数据，0对应第一个边沿，1对应第二个边沿)</li></ul><p>CPOL 和 CPHA 的4中组合：</p><table><thead><tr><th>模式</th><th>组合值</th></tr></thead><tbody><tr><td>1</td><td>CPOL=0,CPHA=0</td></tr><tr><td>2</td><td>CPOL=0,CPHA=1</td></tr><tr><td>3</td><td>CPOL=1,CPHA=0</td></tr><tr><td>4</td><td>CPOL=1,CPHA=1</td></tr></tbody></table><ul><li><p>CPHA=0，表示第一个边沿采集数据</p><ul><li>对于 CPOL=0，IDLE时为低电平，第一个边沿是从低变到高，所以是上升沿</li><li>对于 CPOL=1, IDLE时为高电平，第一个边沿是从高变到低，所以是下降沿</li></ul></li><li><p>CPHA=1，代表第二个边沿采集数据</p><ul><li>对于 CPOL=0，IDLE时为低电平，第二个边沿是从高变到低，所以是下降沿</li><li>对于 CPOL=1, IDLE时为高电平，第二个边沿是从低变到高，所以是上升沿</li></ul></li></ul><p>最后来看一下S3C2440的SPI的CPOL和CPHA，结合前面讲的理论知识，下面的图就很好理解啦！ <img src="'+g+'" alt=""></p><h2 id="iic-协议" tabindex="-1"><a class="header-anchor" href="#iic-协议" aria-hidden="true">#</a> IIC 协议</h2><p><code>IIC</code> 通信协议有2个通信引脚，一个 SDA (数据) 和 一个 SCL(时钟)。</p>',45),u=[S];function I(m,C){return o(),d("div",null,u)}const _=e(h,[["render",I],["__file","通信协议.html.vue"]]);export{_ as default};
